// MARK: - Password Hashing Service

class PasswordHashingService {
    
    static let shared = PasswordHashingService()
    
    private let saltLength = 32
    private let hashIterations: UInt32 = 10000
    private let derivedKeyLength = 64
    
    private init() {}
    
    // Generate a cryptographically secure random salt
    func generateSalt() -> Data {
        var salt = Data(count: saltLength)
        salt.withUnsafeMutableBytes { bufferPointer in
            guard let baseAddress = bufferPointer.baseAddress else { return }
            _ = SecRandomCopyBytes(kSecRandomDefault, saltLength, baseAddress)
        }
        return salt
    }
    
    // Hash password using PBKDF2 with HMAC-SHA512 (available on all iOS versions 10+)
    func hashPassword(_ password: String, salt: Data) -> Data? {
        guard let passwordData = password.data(using: .utf8) else { return nil }
        
        var derivedKey = Data(count: derivedKeyLength)
        
        let result = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            salt.withUnsafeBytes { saltBytes in
                passwordData.withUnsafeBytes { passwordBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                        passwordData.count,
                        saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                        hashIterations,
                        derivedKeyBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        derivedKeyLength
                    )
                }
            }
        }
        
        guard result == kCCSuccess else { return nil }
        return derivedKey
    }
    
    // Create a combined hash string: iterations$salt$hash (all base64 encoded where needed)
    func createPasswordHash(_ password: String) -> String? {
        let salt = generateSalt()
        guard let hash = hashPassword(password, salt: salt) else { return nil }
        
        let saltBase64 = salt.base64EncodedString()
        let hashBase64 = hash.base64EncodedString()
        
        return "\(hashIterations)$\(saltBase64)$\(hashBase64)"
    }
    
    // Verify a password against a stored hash string
    func verifyPassword(_ password: String, againstHash storedHash: String) -> Bool {
        let components = storedHash.components(separatedBy: "$")
        guard components.count == 3,
              let _ = UInt32(components[0]),
              let salt = Data(base64Encoded: components[1]),
              let expectedHash = Data(base64Encoded: components[2]) else {
            return false
        }
        
        guard let computedHash = hashPassword(password, salt: salt) else { return false }
        
        // Constant-time comparison to prevent timing attacks
        return constantTimeCompare(computedHash, expectedHash)
    }
    
    // Constant-time comparison to mitigate timing attacks
    private func constantTimeCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else { return false }
        
        var result: UInt8 = 0
        for i in 0..<a.count {
            result |= a[i] ^ b[i]
        }
        return result == 0
    }
}

// MARK: - Secure Local Storage (Keychain wrapper)

class SecureStorageService {
    
    static let shared = SecureStorageService()
    
    private let service = "com.passwordstorage.app"
    
    private init() {}
    
    // Save data to Keychain
    func save(key: String, data: Data) -> Bool {
        // Delete existing item first
        delete(key: key)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    // Save string to Keychain
    func saveString(key: String, value: String) -> Bool {
        guard let data = value.data(using: .utf8) else { return false }
        return save(key: key, data: data)
    }
    
    // Load data from Keychain
    func load(key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
    
    // Load string from Keychain
    func loadString(key: String) -> String? {
        guard let data = load(key: key) else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    // Delete from Keychain
    @discardableResult
    func delete(key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess || status == errSecItemNotFound
    }
    
    // Check if key exists
    func exists(key: String) -> Bool {
        return load(key: key) != nil
    }
    
    // Get all stored account keys
    func allKeys() -> [String] {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess,
              let items = result as? [[String: Any]] else {
            return []
        }
        
        return items.compactMap { $0[kSecAttrAccount as String] as? String }
    }
}

// MARK: - Password Manager

class PasswordManager {
    
    static let shared = PasswordManager()
    
    private let hashService = PasswordHashingService.shared
    private let storage = SecureStorageService.shared
    
    private let masterPasswordKey = "master_password_hash"
    private let credentialPrefix = "credential_"
    private let credentialListKey = "credential_list"
    
    private init() {}
    
    // MARK: - Master Password Management
    
    var isMasterPasswordSet: Bool {
        return storage.exists(key: masterPasswordKey)
    }
    
    func setMasterPassword(_ password: String) -> Bool {
        guard let hash = hashService.createPasswordHash(password) else { return false }
        return storage.saveString(key: masterPasswordKey, value: hash)
    }
    
    func verifyMasterPassword(_ password: String) -> Bool {
        guard let storedHash = storage.loadString(key: masterPasswordKey) else { return false }
        return hashService.verifyPassword(password, againstHash: storedHash)
    }
    
    func changeMasterPassword(current: String, new: String) -> Bool {
        guard verifyMasterPassword(current) else { return false }
        return setMasterPassword(new)
    }
    
    // MARK: - Credential Storage
    
    func saveCredential(siteName: String, username: String, password: String, masterPassword: String) -> Bool {
        guard verifyMasterPassword(masterPassword) else { return false }
        
        // Hash the stored password
        guard let passwordHash = hashService.createPasswordHash(password) else { return false }
        
        let credential: [String: String] = [
            "site": siteName,
            "username": username,
            "passwordHash": passwordHash,
            "createdAt": ISO8601DateFormatter().string(from: Date())
        ]
        
        guard let data = try? JSONSerialization.data(withJSONObject: credential, options: []) else {
            return false
        }
        
        let key = credentialPrefix + siteName.lowercased().replacingOccurrences(of: " ", with: "_")
        let saved = storage.save(key: key, data: data)
        
        if saved {
            addToCredentialList(key)
        }
        
        return saved
    }
    
    func verifyCredentialPassword(siteName: String, password: String) -> Bool {
        let key = credentialPrefix + siteName.lowercased().replacingOccurrences(of: " ", with: "_")
        
        guard let data = storage.load(key: key),
              let credential = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: String],
              let storedHash = credential["passwordHash"] else {
            return false
        }
        
        return hashService.verifyPassword(password, againstHash: storedHash)
    }
    
    func getCredential(siteName: String) -> [String: String]? {
        let key = credentialPrefix + siteName.lowercased().replacingOccurrences(of: " ", with: "_")
        
        guard let data = storage.load(key: key),
              let credential = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: String] else {
            return nil
        }
        
        return credential
    }
    
    func deleteCredential(siteName: String) -> Bool {
        let key = credentialPrefix + siteName.lowercased().replacingOccurrences(of: " ", with: "_")
        removeFromCredentialList(key)
        return storage.delete(key: key)
    }
    
    func getAllCredentials() -> [[String: String]] {
        let keys = getCredentialList()
        var credentials: [[String: String]] = []
        
        for key in keys {
            if let data = storage.load(key: key),
               let credential = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: String] {
                credentials.append(credential)
            }
        }
        
        return credentials
    }
    
    // MARK: - Credential List Management
    
    private func getCredentialList() -> [String] {
        guard let data = storage.load(key: credentialListKey),
              let list = try? JSONSerialization.jsonObject(with: data, options: []) as? [String] else {
            return []
        }
        return list
    }
    
    private func saveCredentialList(_ list: [String]) {
        guard let data = try? JSONSerialization.data(withJSONObject: list, options: []) else { return }
        storage.save(key: credentialListKey, data: data)
    }
    
    private func addToCredentialList(_ key: String) {
        var list = getCredentialList()
        if !list.contains(key) {
            list.append(key)
            saveCredentialList(list)
        }
    }
    
    private func removeFromCredentialList(_ key: String) {
        var list = getCredentialList()
        list.removeAll { $0 == key }
        saveCredentialList(list)
    }
    
    // Reset everything
    func resetAll() {
        let keys = getCredentialList()
        for key in keys {
            storage.delete(key: key)
        }
        storage.delete(key: credentialListKey)
        storage.delete(key: masterPasswordKey)
    }
}

