    }
    
    // MARK: - Actions
    
    @objc private func masterPasswordAction() {
        guard let password = masterPasswordField.text, !password.isEmpty else {
            showAlert(title: "Error", message: "Please enter a master password.")
            return
        }
        
        if !passwordManager.isMasterPasswordSet {
            // Create new master password
            guard password.count >= 8 else {
                showAlert(title: "Weak Password", message: "Master password must be at least 8 characters.")
                return
            }
            
            if passwordManager.setMasterPassword(password) {
                isAuthenticated = true
                showAlert(title: "Success", message: "Master password created successfully!")
            } else {
                showAlert(title: "Error", message: "Failed to create master password.")
            }
        } else if isAuthenticated {
            // Lock vault
            isAuthenticated = false
        } else {
            // Verify and unlock
            if passwordManager.verifyMasterPassword(password) {
                isAuthenticated = true
                showAlert(title: "Success", message: "Vault unlocked successfully!")
            } else {
                showAlert(title: "Error", message: "Incorrect master password.")
            }
        }
        
        masterPasswordField.text = ""
        updateUIState()
    }
    
    @objc private func saveCredentialAction() {
        guard isAuthenticated else {
            showAlert(title: "Error", message: "Please authenticate first.")
            return
        }
        
        guard let siteName = siteNameField.text, !siteName.isEmpty,
              let username = usernameField.text, !username.isEmpty,
              let password = passwordField.text, !password.isEmpty else {
            showAlert(title: "Error", message: "Please fill in all fields.")
            return
        }
        
        guard let masterPassword = promptForMasterPassword() else {
            // Use a simulated approach - in production you'd use a dialog
            let alert = UIAlertController(title: "Confirm", message: "Enter master password to save", preferredStyle: .alert)
            alert.addTextField { field in
                field.isSecureTextEntry = true
                field.placeholder = "Master password"
            }
            alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
            alert.addAction(UIAlertAction(title: "Save", style: .default) { [weak self] _ in
                guard let self = self,
                      let masterPwd = alert.textFields?.first?.text,
                      !masterPwd.isEmpty else { return }
                
                if self.passwordManager.saveCredential(
                    siteName: siteName,
                    username: username,
                    password: password,
                    masterPassword: masterPwd
                ) {
                    self.showAlert(title: "Success", message: "Credential saved securely!")
                    self.siteNameField.text = ""
                    self.usernameField.text = ""
                    self.passwordField.text = ""
                    self.refreshCredentialsList()
                } else {
                    self.showAlert(title: "Error", message: "Failed to save credential. Check master password.")
                }
            })
            present(alert, animated: true)
            return
        }
        _ = masterPassword // Unused in this path
    }
    
    private func promptForMasterPassword() -> String? {
        // This is handled via alert controller in the calling method
        return nil
    }
    
    @objc private func verifyPasswordAction() {
        guard let siteName = verifySiteField.text, !siteName.isEmpty,
              let password = verifyPasswordField.text, !password.isEmpty else {
            showAlert(title: "Error", message: "Please fill in site name and password.")
            return
        }
        
        let isValid = passwordManager.verifyCredentialPassword(siteName: siteName, password: password)
        
        if isValid {
            showAlert(title: "✅ Match!", message: "The password matches the stored credential for \(siteName).")
        } else {
            showAlert(title: "❌ No Match", message: "The password does not match or no credential found for \(siteName).")
        }
        
        verifyPasswordField.text = ""
    }
    
    @objc private func resetAction() {
        let alert = UIAlertController(
            title: "Reset All Data",
            message: "This will delete all stored passwords and the master password. This cannot be undone.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Reset", style: .destructive) { [weak self] _ in
            self?.passwordManager.resetAll()
            self?.isAuthenticated = false
            self?.updateUIState()
            self?.showAlert(title: "Reset Complete", message: "All data has been erased.")
        })
        present(alert, animated: true)
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
}

// MARK: - UITableViewDataSource & Delegate

extension PasswordStorageViewController: UITableViewDataSource, UITableViewDelegate {
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return credentials.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "CredentialCell", for: indexPath)
        let credential = credentials[indexPath.row]
        
        let site = credential["site"] ?? "Unknown"
        let username = credential["username"] ?? "Unknown"
        let created = credential["createdAt"] ?? ""
        
        cell.textLabel?.text = "🔐 \(site) — \(username)"
        cell.textLabel?.numberOfLines = 2
        cell.textLabel?.font = UIFont.systemFont(ofSize: 14)
        cell.detailTextLabel?.text = created
        
        return cell
    }
    
    func tableView(_ tableView: UITableView, commit editingStyle: UITableViewCell.EditingStyle, forRowAt indexPath: IndexPath) {
        if editingStyle == .delete {
            if let siteName = credentials[indexPath.row]["site"] {
                _ = passwordManager.deleteCredential(siteName: siteName)
                refreshCredentialsList()
            }
        }
    }
    
    func tableView(_ tableView: UITableView, titleForDeleteConfirmationButtonForRowAt indexPath: IndexPath) -> String? {
        return "Delete"
    }
}

